-- MoneyGraph example dataset — exported snapshot of the real accumulated graph.
-- Generated by scripts/export_public_seed.py (private repo, run manually, not part of any CI/deploy).
-- Curated: top-N nodes by edge degree + edges/events/sources from the last 2 months at
-- snapshot time. Internal pipeline notes in raw_excerpt (ticket references, reclassification
-- reasoning) are blanked; genuine source quotes are kept verbatim. No candidates, news_feed,
-- pipeline_runs, or other accumulated/internal-only data ships.
--
-- Wrapped in one transaction: edges require a backing `sources` row at COMMIT time
-- (enforce_edge_has_source deferred trigger) — order within the transaction doesn't matter,
-- but everything must land before commit.

BEGIN;

-- 100 nodes, top-100 by edge degree (snapshot export,)

-- 132 edges between selected nodes, last_confirmed within 2 months of snapshot

-- 208 investment_events for selected edges (raw_excerpt redacted where it's an internal pipeline note, not a public quote)

-- 353 sources backing the selected edges (required by enforce_edge_has_source trigger)

-- 94 node_aliases for selected nodes

-- 41 node_facts for selected nodes

-- 29 node_tickers for selected nodes


COMMIT;
